//! Conformance tests for ferrotorch-cubecl — Layer 3.
//!
//! Tracking issue: <https://github.com/dollspace-gay/ferrotorch/issues/860>
//!
//! Reference: ferrotorch-core CPU (same operation, same inputs, same output
//! within tolerance). Since ferrotorch-cubecl is a portable GPU backend, the
//! contract is "same result as CPU within tolerance."
//!
//! Reference rev: f1cd5d540e7531ccbd21f83cd6c70e8705409017
//!
//! Fixtures generated by `scripts/regenerate_cubecl_fixtures.py`.
//!
//! Organisation:
//! - CubeDevice / CubeRuntime structural tests (Layer 3, no GPU required)
//! - GgufBlockKind structural tests (no GPU required)
//! - DfaMaskInputs structural constructor test (no GPU required)
//! - GPU ops (cascade_skip when no backend active in test environment)
//!
//! cascade_skip convention: `#[ignore = "cascade_skip #NNN: reason"]`
//! Cross-link issues are filed for divergences found; DO NOT FIX inline.

use std::path::PathBuf;

use serde::Deserialize;
use serde_json::Value;

use ferrotorch_cubecl::{CubeDevice, CubeRuntime, DfaMaskInputs, GgufBlockKind};

// ---------------------------------------------------------------------------
// Fixture loading
// ---------------------------------------------------------------------------

#[derive(Debug, Deserialize)]
struct FixtureFile {
    #[allow(dead_code, reason = "metadata kept for diagnostics")]
    metadata: Value,
    fixtures: Vec<Fixture>,
}

#[derive(Debug, Deserialize, Clone)]
struct Fixture {
    op: String,
    #[serde(default)]
    a: Option<Vec<f32>>,
    #[serde(default)]
    b: Option<Vec<f32>>,
    #[serde(default)]
    x: Option<Vec<f32>>,
    #[serde(default)]
    shape: Option<Vec<usize>>,
    #[serde(default)]
    m: Option<usize>,
    #[serde(default)]
    k: Option<usize>,
    #[serde(default)]
    n: Option<usize>,
    #[serde(default)]
    degree: Option<usize>,
    #[serde(default)]
    expected: Option<Vec<f32>>,
    #[serde(default)]
    atol: Option<f64>,
    // Structural fixtures use freeform JSON
    #[serde(default)]
    cases: Option<Value>,
}

fn load_fixtures() -> FixtureFile {
    let p = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("conformance")
        .join("fixtures.json");
    let bytes = std::fs::read(&p).unwrap_or_else(|e| {
        panic!(
            "read {} failed: {e}. Run python3 scripts/regenerate_cubecl_fixtures.py first.",
            p.display()
        )
    });
    serde_json::from_slice(&bytes).unwrap_or_else(|e| panic!("parse {}: {e}", p.display()))
}

fn find(file: &FixtureFile, op: &str) -> Fixture {
    file.fixtures
        .iter()
        .find(|f| f.op == op)
        .unwrap_or_else(|| panic!("no fixture with op={op:?}"))
        .clone()
}

// ---------------------------------------------------------------------------
// Tolerance helper
// ---------------------------------------------------------------------------

fn assert_slice_close(actual: &[f32], expected: &[f32], atol: f32, label: &str) {
    assert_eq!(
        actual.len(),
        expected.len(),
        "{label}: length mismatch actual={} expected={}",
        actual.len(),
        expected.len()
    );
    for (i, (a, e)) in actual.iter().zip(expected.iter()).enumerate() {
        // Handle NaN-identity: if both are NaN treat as equal.
        if a.is_nan() && e.is_nan() {
            continue;
        }
        let diff = (a - e).abs();
        assert!(
            diff <= atol,
            "{label}[{i}]: actual={a:.8e} expected={e:.8e} diff={diff:.3e} > atol={atol:.3e}"
        );
    }
}

// ---------------------------------------------------------------------------
// Helper: try to get a wgpu runtime, skip gracefully when not available.
// Mirrors the probe in ops.rs unit tests.
// ---------------------------------------------------------------------------

fn try_wgpu_runtime() -> Option<CubeRuntime> {
    let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
        CubeRuntime::new(CubeDevice::Wgpu(0)).ok()
    }));
    match result {
        Ok(Some(rt)) => Some(rt),
        _ => {
            eprintln!(
                "[ferrotorch-cubecl conformance] cubecl backend not active in test environment; \
                 skipping GPU conformance test"
            );
            None
        }
    }
}

// ---------------------------------------------------------------------------
// read_back helper — thin wrapper that compiles even without a backend
// feature flag. When a backend IS compiled, delegates to CubeRuntime::read_f32s.
// When no backend is compiled, this path is unreachable because try_wgpu_runtime()
// always returns None. Defined unconditionally so all call sites compile.
// ---------------------------------------------------------------------------

#[allow(
    unused_variables,
    reason = "unreachable when no backend feature; args kept for call-site symmetry"
)]
fn read_back(rt: &CubeRuntime, handle: cubecl::server::Handle, n: usize) -> Vec<f32> {
    // SAFETY: this function is only ever called after `try_wgpu_runtime()`
    // returned `Some`, which is only possible when a backend feature is compiled.
    #[cfg(any(feature = "wgpu", feature = "cuda", feature = "rocm"))]
    {
        rt.read_f32s(handle, n).expect("read_f32s failed")
    }
    #[cfg(not(any(feature = "wgpu", feature = "cuda", feature = "rocm")))]
    {
        unreachable!(
            "read_back called without a backend feature — this should be dead code \
             because try_wgpu_runtime() always returns None without a backend"
        )
    }
}

