#[test]
fn cube_device_ordinal_matches_fixtures() {
    let file = load_fixtures();
    let f = find(&file, "cube_device_ordinal");
    let cases = f.cases.as_ref().expect("cases").as_array().expect("array");
    for case in cases {
        let variant = case["variant"].as_str().expect("variant");
        let ordinal_arg = case["ordinal_arg"].as_u64().expect("ordinal_arg") as usize;
        let expected = case["expected_ordinal"].as_u64().expect("expected_ordinal") as usize;
        let dev = match variant {
            "Cuda" => CubeDevice::Cuda(ordinal_arg),
            "Wgpu" => CubeDevice::Wgpu(ordinal_arg),
            "Rocm" => CubeDevice::Rocm(ordinal_arg),
            other => panic!("unknown variant {other:?}"),
        };
        assert_eq!(
            dev.ordinal(),
            expected,
            "CubeDevice::{variant}({ordinal_arg}).ordinal() should be {expected}"
        );
    }
}

