#[test]
fn cube_runtime_is_available_compile_flag_consistent() {
    // is_available() is a compile-time cfg!(...) check; it should be stable.
    let available = CubeRuntime::is_available();
    // When no GPU feature is compiled in, auto() must return None (never panics).
    if !available {
        let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(CubeRuntime::auto));
        let is_none = matches!(result, Ok(None) | Err(_));
        assert!(
            is_none,
            "CubeRuntime::is_available() returned false but auto() returned Some"
        );
    } else {
        // Documented contract: is_available() == true ⇒ auto() = Some(_).
        // Phase 9 (#1045): without this branch the test was a no-op when a
        // backend feature was compiled; a stub `auto()` that returned None
        // would have passed silently.
        let rt = CubeRuntime::auto();
        assert!(
            rt.is_some(),
            "CubeRuntime::is_available() returned true but auto() returned None"
        );
    }
}

#[test]
fn cube_runtime_new_without_backend_feature_errors() {
    // Phase 9 (#1046): pin the public signature of `CubeRuntime::new` at
    // compile time so behavioural drift (e.g. an arity change, or a return-type
    // swap that would silently bypass the error contract this test asserts) is
    // caught regardless of whether a backend feature is compiled in. This
    // assertion runs unconditionally — the typed fn-pointer cast is a
    // compile-time check.
    let _new_signature: fn(CubeDevice) -> ferrotorch_core::FerrotorchResult<CubeRuntime> =
        CubeRuntime::new;

    // #1083: when no backend feature is compiled, `CubeRuntime::new` must
    // return Err. When a backend IS compiled, exercising the Err-path of
    // `CubeRuntime::new` directly is impossible (a real adapter would
    // legitimately succeed) — but we still verify the contract structurally
    // by constructing a stub runtime via `new_for_testing` and asserting
    // it never claims a real backend.
    if CubeRuntime::is_available() {
        // Stub runtime path: confirm `new_for_testing` does not pretend
        // to be a real backend. Reaching kernel dispatch with this
        // runtime is a test-discipline bug; pre-dispatch paths (shape
        // check, signature pin) must fire first.
        let stub = CubeRuntime::new_for_testing(CubeDevice::Wgpu(0));
        assert_eq!(*stub.device(), CubeDevice::Wgpu(0));
        assert!(
            matches!(stub.client(), ferrotorch_cubecl::CubeClient::Stub),
            "new_for_testing must yield a Stub client, never a real backend"
        );
        return;
    }
    let result = CubeRuntime::new(CubeDevice::Wgpu(0));
    assert!(
        result.is_err(),
        "CubeRuntime::new() must return Err when no backend feature is compiled"
    );
}

