// ---------------------------------------------------------------------------
// Shape-error conformance (no GPU execution needed for the error path)
// ---------------------------------------------------------------------------

/// Phase 9 (#1048, #1049): the structural shape of every binary `portable_*`
/// op exposed by `ferrotorch-cubecl`. Used as a typed fn-pointer pin so that
/// a silent arity / return-type drift fails compilation even when the
/// behavioural assertion in the test body is short-circuited (no backend).
type PortableBinaryOp =
    fn(
        &ferrotorch_core::Tensor<f32>,
        &ferrotorch_core::Tensor<f32>,
        &CubeRuntime,
    ) -> ferrotorch_core::FerrotorchResult<(cubecl::server::Handle, Vec<usize>)>;

#[test]
fn portable_add_shape_mismatch_returns_error() {
    // Phase 9 (#1048): pin the public signature of `portable_add` at compile
    // time so a silent arity / return-type drift (e.g. removing the `&CubeRuntime`
    // arg, or returning `()` instead of `FerrotorchResult<...>`) is caught even
    // in the no-backend test environment where the behavioural assertion below
    // is short-circuited.
    let _add_signature: PortableBinaryOp = ferrotorch_cubecl::ops::portable_add;

    // #1083 closed: CPU-side shape validation in `portable_add` is now
    // unconditionally reachable via `CubeRuntime::new_for_testing`, which
    // returns a runtime backed by `CubeClient::Stub`. The pre-dispatch
    // shape check fires before any kernel arm — Stub never reaches
    // dispatch. Fall back to a real wgpu runtime when one is available
    // so the live-path assertion still gets exercised on hardware.
    let rt =
        try_wgpu_runtime().unwrap_or_else(|| CubeRuntime::new_for_testing(CubeDevice::Wgpu(0)));
    let a = ferrotorch_core::tensor(&[1.0_f32, 2.0, 3.0]).expect("a");
    let b = ferrotorch_core::tensor(&[1.0_f32, 2.0]).expect("b");
    let err = ferrotorch_cubecl::ops::portable_add(&a, &b, &rt);
    assert!(
        err.is_err(),
        "portable_add must return Err on shape mismatch"
    );
}

#[test]
fn portable_matmul_inner_dim_mismatch_returns_error() {
    // Phase 9 (#1049): pin the public signature of `portable_matmul` at
    // compile time so a silent arity / return-type drift is caught even in
    // the no-backend test environment where the behavioural assertion below
    // is short-circuited.
    let _matmul_signature: PortableBinaryOp = ferrotorch_cubecl::ops::portable_matmul;

    // #1083 closed: CPU-side inner-dim check in `portable_matmul` is now
    // unconditionally reachable via `CubeRuntime::new_for_testing` — the
    // Stub client never reaches kernel dispatch, so the shape check
    // fires deterministically in any backend configuration.
    let rt =
        try_wgpu_runtime().unwrap_or_else(|| CubeRuntime::new_for_testing(CubeDevice::Wgpu(0)));
    let a = ferrotorch_core::from_vec(vec![1.0_f32; 6], &[2, 3]).expect("a");
    let b = ferrotorch_core::from_vec(vec![1.0_f32; 8], &[4, 2]).expect("b");
    let err = ferrotorch_cubecl::ops::portable_matmul(&a, &b, &rt);
    assert!(
        err.is_err(),
        "portable_matmul must return Err on inner dim mismatch"
    );
}

// ---------------------------------------------------------------------------
// CubeDevice method coverage — explicit qualified-path calls so the surface
// gate's substring matcher finds `CubeDevice::ordinal` and `CubeDevice::backend_name`.
// The fixture-based tests above call the methods via a local `dev` binding,
// which doesn't contain the `Type::method` key the gate requires.
// ---------------------------------------------------------------------------

#[test]
fn cube_device_ordinal_via_qualified_path() {
    // Explicit `CubeDevice::ordinal` call so the surface gate finds this item.
    assert_eq!(CubeDevice::Cuda(5).ordinal(), 5);
    assert_eq!(CubeDevice::Wgpu(2).ordinal(), 2);
    assert_eq!(CubeDevice::Rocm(0).ordinal(), 0);
    // Same calls written as `CubeDevice::ordinal(&dev)` to satisfy the surface
    // gate's substring matcher. Phase 9 (#1047): previously this was
    // `let _ = CubeDevice::ordinal(&dev);` which discarded the return value
    // and let stub implementations slip through silently. Now the assertion
    // discriminates: a stub returning 0/usize::MAX/etc. for `Wgpu(1)` fails.
    let dev = CubeDevice::Wgpu(1);
    assert_eq!(CubeDevice::ordinal(&dev), 1);
}

#[test]
fn cube_device_backend_name_via_qualified_path() {
    // Explicit `CubeDevice::backend_name` call so the surface gate finds this item.
    assert_eq!(CubeDevice::backend_name(&CubeDevice::Cuda(0)), "cuda");
    assert_eq!(CubeDevice::backend_name(&CubeDevice::Wgpu(0)), "wgpu");
    assert_eq!(CubeDevice::backend_name(&CubeDevice::Rocm(0)), "rocm");
}

