// ---------------------------------------------------------------------------
// split_q* host-side conformance (CPU-only, no GPU backend required).
//
// Reference: the Q4_0 / Q4_1 / Q5_0 / Q5_1 / Q8_0 / Q8_1 block layouts from
// the GGUF spec. Block structures:
//   Q4_0: [f16 scale (2 B)] [16 B nibbles]                             = 18 B
//   Q4_1: [f16 scale (2 B)] [f16 min (2 B)] [16 B nibbles]            = 20 B
//   Q5_0: [f16 scale (2 B)] [qh u32 (4 B)] [16 B low nibbles]         = 22 B
//   Q5_1: [f16 scale (2 B)] [f16 min (2 B)] [qh u32 (4 B)] [nibbles]  = 24 B
//   Q8_0: [f16 scale (2 B)] [32 i8 bytes]                              = 34 B
//   Q8_1: [f32 scale (4 B)] [f32 min (4 B)] [32 i8 bytes]             = 40 B
// ---------------------------------------------------------------------------

use ferrotorch_cubecl::{
    split_q4_0_blocks, split_q4_1_blocks, split_q5_0_blocks, split_q5_1_blocks, split_q8_0_blocks,
    split_q8_1_blocks,
};

#[test]
fn split_q4_0_blocks_round_trip_scale_and_nibbles() {
    // Craft a single Q4_0 block: scale = f16(1.0) → bytes [0x00, 0x3C],
    // nibble payload = 16 bytes of 0xAB (arbitrary).
    let scale_bytes = half::f16::from_f32(1.0).to_bits().to_le_bytes();
    let mut block = vec![scale_bytes[0], scale_bytes[1]];
    block.extend_from_slice(&[0xABu8; 16]);
    assert_eq!(block.len(), 18);

    let (scales, nibbles) = split_q4_0_blocks(&block, 1);
    assert_eq!(scales.len(), 1);
    assert!((scales[0] - 1.0f32).abs() < 1e-3, "scale round-trip");
    assert_eq!(nibbles.len(), 4);
    // Each u32 should be 0xABABABAB (four 0xAB bytes packed LE).
    let expected_word = u32::from_le_bytes([0xAB, 0xAB, 0xAB, 0xAB]);
    for w in &nibbles {
        assert_eq!(*w, expected_word);
    }
}

#[test]
fn split_q4_1_blocks_round_trip_scale_min_nibbles() {
    // Q4_1 block: scale=f16(2.0), min=f16(0.5), nibbles=0x12 × 16.
    let scale_bytes = half::f16::from_f32(2.0).to_bits().to_le_bytes();
    let min_bytes = half::f16::from_f32(0.5).to_bits().to_le_bytes();
    let mut block = vec![scale_bytes[0], scale_bytes[1], min_bytes[0], min_bytes[1]];
    block.extend_from_slice(&[0x12u8; 16]);
    assert_eq!(block.len(), 20);

    let (scales, mins, nibbles) = split_q4_1_blocks(&block, 1);
    assert_eq!(scales.len(), 1);
    assert_eq!(mins.len(), 1);
    assert!((scales[0] - 2.0f32).abs() < 1e-3, "scale");
    assert!((mins[0] - 0.5f32).abs() < 1e-3, "min");
    assert_eq!(nibbles.len(), 4);
    let expected_word = u32::from_le_bytes([0x12, 0x12, 0x12, 0x12]);
    for w in &nibbles {
        assert_eq!(*w, expected_word);
    }
}

#[test]
fn split_q5_0_blocks_round_trip_scale_qh_nibbles() {
    // Q5_0 block: scale=f16(1.5), qh=0x0F0F0F0F u32 LE, nibbles=0x55 × 16.
    let scale_bytes = half::f16::from_f32(1.5).to_bits().to_le_bytes();
    let qh: u32 = 0x0F0F_0F0F;
    let qh_bytes = qh.to_le_bytes();
    let mut block = vec![scale_bytes[0], scale_bytes[1]];
    block.extend_from_slice(&qh_bytes);
    block.extend_from_slice(&[0x55u8; 16]);
    assert_eq!(block.len(), 22);

    let (scales, qh_out, nibbles) = split_q5_0_blocks(&block, 1);
    assert_eq!(scales.len(), 1);
    assert!((scales[0] - 1.5f32).abs() < 1e-3, "scale");
    assert_eq!(qh_out.len(), 1);
    assert_eq!(qh_out[0], qh);
    assert_eq!(nibbles.len(), 4);
    let expected_word = u32::from_le_bytes([0x55, 0x55, 0x55, 0x55]);
    for w in &nibbles {
        assert_eq!(*w, expected_word);
    }
}

#[test]
fn split_q5_1_blocks_round_trip_scale_min_qh_nibbles() {
    // Q5_1 block: scale=f16(1.0), min=f16(0.25), qh=0xDEAD_BEEF, nibbles=0x99 × 16.
    let scale_bytes = half::f16::from_f32(1.0).to_bits().to_le_bytes();
    let min_bytes = half::f16::from_f32(0.25).to_bits().to_le_bytes();
    let qh: u32 = 0xDEAD_BEEF;
    let qh_bytes = qh.to_le_bytes();
    let mut block = vec![scale_bytes[0], scale_bytes[1], min_bytes[0], min_bytes[1]];
    block.extend_from_slice(&qh_bytes);
    block.extend_from_slice(&[0x99u8; 16]);
    assert_eq!(block.len(), 24);

    let (scales, mins, qh_out, nibbles) = split_q5_1_blocks(&block, 1);
    assert_eq!(scales.len(), 1);
    assert_eq!(mins.len(), 1);
    assert!((scales[0] - 1.0f32).abs() < 1e-3, "scale");
    assert!((mins[0] - 0.25f32).abs() < 1e-3, "min");
    assert_eq!(qh_out.len(), 1);
    assert_eq!(qh_out[0], qh);
    assert_eq!(nibbles.len(), 4);
    let expected_word = u32::from_le_bytes([0x99, 0x99, 0x99, 0x99]);
    for w in &nibbles {
        assert_eq!(*w, expected_word);
    }
}

#[test]
fn split_q8_0_blocks_round_trip_scale_and_bytes() {
    // Q8_0 block: scale=f16(0.5), 32 bytes = 0x01 0x02 ... alternating.
    let scale_bytes = half::f16::from_f32(0.5).to_bits().to_le_bytes();
    let mut block = vec![scale_bytes[0], scale_bytes[1]];
    // 32 payload bytes = 0x01 0x02 repeating
    let payload: Vec<u8> = (0..32u8).map(|i| i + 1).collect();
    block.extend_from_slice(&payload);
    assert_eq!(block.len(), 34);

    let (scales, packed) = split_q8_0_blocks(&block, 1);
    assert_eq!(scales.len(), 1);
    assert!((scales[0] - 0.5f32).abs() < 1e-3, "scale");
    // 32 bytes → 8 u32s
    assert_eq!(packed.len(), 8);
    // First u32 should be LE pack of bytes 1,2,3,4
    let expected_first = u32::from_le_bytes([1, 2, 3, 4]);
    assert_eq!(packed[0], expected_first);
}

#[test]
fn split_q8_1_blocks_round_trip_scale_min_and_bytes() {
    // Q8_1 block: f32 scale=1.0, f32 min=0.0, 32 bytes = 0x7F × 32.
    let scale_f32: f32 = 1.0;
    let min_f32: f32 = 0.0;
    let mut block = Vec::new();
    block.extend_from_slice(&scale_f32.to_le_bytes());
    block.extend_from_slice(&min_f32.to_le_bytes());
    block.extend_from_slice(&[0x7Fu8; 32]);
    assert_eq!(block.len(), 40);

    let (scales, mins, packed) = split_q8_1_blocks(&block, 1);
    assert_eq!(scales.len(), 1);
    assert_eq!(mins.len(), 1);
    assert!((scales[0] - 1.0f32).abs() < 1e-6, "scale");
    assert!((mins[0] - 0.0f32).abs() < 1e-6, "min");
    assert_eq!(packed.len(), 8);
    let expected_word = u32::from_le_bytes([0x7F, 0x7F, 0x7F, 0x7F]);
    for w in &packed {
        assert_eq!(*w, expected_word);
    }
}

